import copy
from collections import deque

def is_valid(grid, n):
    for i in range(n):
        for j in range(n):
            if grid[i][j] == '.':
                continue
            count = 0
            for dx, dy in [(-1,0),(1,0),(0,-1),(0,1)]:
                ni, nj = i+dx, j+dy
                if 0 <= ni < n and 0 <= nj < n:
                    if grid[ni][nj] == grid[i][j]:
                        count += 1
            if count != 2:
                return False
    return True

def solve_mosaic(grid, n):
    # Check for existing invalid cells
    for i in range(n):
        for j in range(n):
            if grid[i][j] != '.':
                count = 0
                for dx, dy in [(-1,0),(1,0),(0,-1),(0,1)]:
                    ni, nj = i+dx, j+dy
                    if 0 <= ni < n and 0 <= nj < n:
                        if grid[ni][nj] == grid[i][j]:
                            count += 1
                if count != 2:
                    return 'NONE', None

    # Try to fill the grid
    # For each cell, determine the color based on neighbors
    # We can use BFS to propagate the colors
    # First, find all cells with known colors
    queue = deque()
    color_grid = [[None for _ in range(n)] for _ in range(n)]
    for i in range(n):
        for j in range(n):
            if grid[i][j] != '.':
                color_grid[i][j] = grid[i][j]
                queue.append((i, j))

    # Directions for neighbors
    directions = [(-1,0),(1,0),(0,-1),(0,1)]

    # BFS to propagate colors
    while queue:
        x, y = queue.popleft()
        for dx, dy in directions:
            nx, ny = x+dx, y+dy
            if 0 <= nx < n and 0 <= ny < n and color_grid[nx][ny] is None:
                # Determine the color based on existing neighbors
                count = 0
                for dx2, dy2 in directions:
                    nx2, ny2 = nx+dx2, ny+dy2
                    if 0 <= nx2 < n and 0 <= ny2 < n:
                        if color_grid[nx2][ny2] is not None:
                            count += 1
                if count == 0:
                    # No neighbors, can't determine color
                    return 'NONE', None
                elif count == 1:
                    # One neighbor, choose the opposite color
                    color_grid[nx][ny] = 'S' if color_grid[nx+dx2][ny+dy2] == 'G' else 'G'
                    queue.append((nx, ny))
                else:
                    # More than one neighbor, check consistency
                    # Check if all neighbors are the same color
                    color = color_grid[nx+dx2][ny+dy2]
                    for dx2, dy2 in directions:
                        nx2, ny2 = nx+dx2, ny+dy2
                        if 0 <= nx2 < n and 0 <= ny2 < n and color_grid[nx2][ny2] is not None:
                            if color_grid[nx2][ny2] != color:
                                return 'NONE', None
                    color_grid[nx][ny] = color
                    queue.append((nx, ny))

    # Check if all cells are filled
    for i in range(n):
        for j in range(n):
            if color_grid[i][j] is None:
                return 'NONE', None

    # Check if the filled grid is valid
    if not is_valid(color_grid, n):
        return 'NONE', None

    # Check for uniqueness
    # Try to change one cell and see if it still works
    for i in range(n):
        for j in range(n):
            if color_grid[i][j] == '.':
                continue
            # Try changing this cell to the opposite color
            temp_grid = [row[:] for row in color_grid]
            temp_grid[i][j] = 'S' if temp_grid[i][j] == 'G' else 'G'
            if is_valid(temp_grid, n):
                return 'MULTIPLE', None

    return 'UNIQUE', color_grid


def main():
    n = int(sys.stdin.readline())
    grid = [list(sys.stdin.readline().strip()) for _ in range(n)]
    result, solution = solve_mosaic(grid, n)
    print(result)
    if result == 'UNIQUE':
        for row in solution:
            print(''.join(row))

if __name__ == '__main__':
    main()"}

