{"code": "import sys

def main():
    T = int(sys.stdin.readline())
    for _ in range(T):
        N = int(sys.stdin.readline())
        scores = {}
        for _ in range(N):
            name, score = sys.stdin.readline().split()
            score = int(score)
            if name in scores:
                scores[name] += score
            else:
                scores[name] = score
        winner = max(scores, key=scores.get)
        print(f"{winner} {scores[winner]}")

if __name__ == "__main__":
    main()"}

