from collections import deque

def main():
    n, m = map(int, sys.stdin.readline().split())
    grid = []
    for _ in range(n):
        grid.append(list(map(int, sys.stdin.readline().split())))

    visited = [[False for _ in range(m)] for _ in range(n)]
    directions = [(0, 1), (1, 0), (0, -1), (-1, 0)]  # East, South, West, North

    def is_wall(tile, direction):
        binary = bin(tile)[2:].zfill(4)
        if direction == 'East':
            return binary[1] == '1'
        elif direction == 'South':
            return binary[2] == '1'
        elif direction == 'West':
            return binary[3] == '1'
        elif direction == 'North':
            return binary[0] == '1'

    def dfs(x, y):
        if x < 0 or x >= n or y < 0 or y >= m or visited[x][y] or is_wall(grid[x][y], 'North'):
            return 0
        visited[x][y] = True
        count = 1
        for dx, dy in directions:
            nx, ny = x + dx, y + dy
            if not is_wall(grid[x][y], 'South' if dx == 1 else 'North' if dx == -1 else 'East' if dy == 1 else 'West'):
                count += dfs(nx, ny)
        return count

    room_sizes = []
    for i in range(n):
        for j in range(m):
            if not visited[i][j] and not is_wall(grid[i][j], 'North'):
                room_sizes.append(dfs(i, j))

    room_sizes.sort(reverse=True)
    print(' '.join(map(str, room_sizes)))

if __name__ == '__main__':
