import math

def min_exchanges(a, x, y):
    def get_steps(num):
        steps = 0
        while num != 0:
            k = num.bit_length()
            num = 2**k - num
            steps += 1
        return steps
    return get_steps(a[x-1]) + get_steps(a[y-1])

def main():
    n = int(sys.stdin.readline())
    a = list(map(int, sys.stdin.readline().split()))
    max_m = -1
    best_pair = (0, 0)
    for i in range(n):
        for j in range(i+1, n):
            m = min_exchanges(a, i, j)
            if m > max_m:
                max_m = m
                best_pair = (i+1, j+1)
    x, y = best_pair
    print(f"{x} {y} {max_m}")

if __name__ == "__main__":
    main()"}

